import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "What is molarity?", a: "Molarity (M) is the concentration of a solution expressed as the number of moles of solute per liter of solution. Formula: M = n/V where n = moles of solute and V = volume in liters. It is the most commonly used concentration unit in chemistry laboratories." },
  { q: "What is the difference between molarity and molality?", a: "Molarity (M) = moles per liter of solution (volume-based, changes with temperature). Molality (m) = moles per kilogram of solvent (mass-based, temperature-independent). Molality is preferred for boiling point elevation (Tb = Kb  x  m) and freezing point depression (Tf = Kf  x  m) calculations." },
  { q: "How do I calculate moles from grams?", a: "Moles = Mass (grams)  x  Molar Mass (g/mol). First find the molar mass by summing atomic masses from the periodic table. Example: NaCl molar mass = 23 (Na) + 35.45 (Cl) = 58.45 g/mol. To dissolve 100 g: 100  x  58.45 = 1.71 moles." },
  { q: "How do I dilute a solution to a lower molarity?", a: "Use the dilution equation: M- = M- where M- is the concentrated solution and M- is the diluted solution. Example: dilute 5 M NaOH to make 500 mL of 1 M: V- = (1  x  500)  x  5 = 100 mL of 5 M stock, then add water to 500 mL total volume." },
  { q: "What are common solution concentrations in chemistry labs?", a: "Common lab concentrations include 0.1 M for analytical work, 1 M for general reactions, 6 M HCl for cleaning solutions, 12 M HCl for concentrated hydrochloric acid, and 18 M H2SO4 for concentrated sulfuric acid. Buffers for biology are typically 0.1-0.5 M." },
  { q: "What is the difference between molar and normal concentration?", a: "Molarity counts total moles of solute per liter. Normality counts moles of reactive units, or equivalents, per liter. For HCl, 1 M equals 1 N. For H2SO4, 1 M equals 2 N because each molecule can donate two hydrogen ions." },
  { q: "How do I make a 1 M solution of NaCl?", a: "NaCl molar mass = 58.44 g/mol. To make 1 L of 1 M NaCl: Weigh 58.44 g of NaCl. Add to a 1-liter volumetric flask. Add approximately 900 mL of distilled water and swirl to dissolve. Add water to the 1 L mark. Mix thoroughly. Always add solute first, then bring to final volume." },
  { q: "What is ppm and how does it relate to molarity?", a: "PPM (parts per million) = mg of solute per liter of solution (for dilute aqueous solutions). To convert ppm to molarity: M = ppm  x  (molar mass  x  1,000). Example: 100 ppm NaCl = 100 mg/L  x  (58.44 g/mol  x  1,000) = 0.00171 M. PPM is commonly used in environmental and water chemistry." },
];

const COMMON_CONCENTRATIONS = [
  ["Seawater (NaCl)", "0.6 M", "~3.5% salt by weight"],
  ["Physiological saline", "0.154 M NaCl", "0.9% - matches blood osmolarity"],
  ["Blood glucose (normal)", "5 mM (0.005 M)", "90 mg/dL"],
  ["Stomach acid (HCl)", "0.1 M", "pH ~1"],
  ["Household vinegar (acetic acid)", "0.83 M", "~5% solution"],
  ["Concentrated HCl", "12 M", "37% by mass"],
  ["Concentrated H2SO4", "18 M", "~98% by mass"],
  ["Ethanol in beer (~5%)", "0.85 M", "~5% by volume"],
];

type SolveFor = "molarity" | "moles" | "volume";

export default function MolarityCalculator() {
  const [solveFor, setSolveFor] = useState<SolveFor>("molarity");
  const [moles, setMoles] = useState(0.5);
  const [volume, setVolume] = useState(1.0);
  const [molarity, setMolarity] = useState(1.0);

  const result = solveFor === "molarity" ? moles / volume
    : solveFor === "moles" ? molarity * volume
    : moles / molarity;
  const unit = solveFor === "molarity" ? "M" : solveFor === "moles" ? "mol" : "L";
  const label = solveFor === "molarity" ? "Molarity" : solveFor === "moles" ? "Moles" : "Volume";

  const concentrationRows = [0.1, 0.5, 1, 2, 5, 10];

  return (
    <>
      <SEOHead
        title="Free Molarity Calculator Online - Calculate Molarity Moles or Volume Instantly | CalcHive"
        description="Free online molarity calculator. Calculate molarity, moles or volume of any solution using M = n/V instantly. 100% free for chemistry students and professionals, no signup required."
        canonical="/molarity-calculator"
        keywords="free molarity calculator, molarity calculator online free, calculate molarity free, moles volume solution calculator free, chemistry molarity formula calculator free"
        category="Science Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-cyan-600 dark:text-cyan-400 bg-cyan-50 dark:bg-cyan-950/50 px-3 py-1 rounded-full mb-4 inline-block">Measurement</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Molarity Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free molarity calculator to calculate molarity free, moles, or volume of a solution using M = n/V. This molarity calculator online free also works as a moles volume solution calculator free and chemistry molarity formula calculator free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <div className="flex gap-2 mb-6">
          {(["molarity", "moles", "volume"] as SolveFor[]).map(v => (
            <button key={v} onClick={() => setSolveFor(v)} className={`flex-1 py-2 rounded-xl text-sm font-semibold border capitalize transition-all ${solveFor === v ? "bg-cyan-600 text-white border-cyan-600" : "bg-card text-muted-foreground border-border hover:border-cyan-400"}`}>Solve for {v}</button>
          ))}
        </div>
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            {solveFor !== "moles" && <SliderInput id="moles" label="Moles of Solute (mol)" value={moles} min={0.001} max={100} step={0.001} onChange={setMoles} format={v => `${v.toFixed(3)} mol`} testId="input-moles" />}
            {solveFor !== "volume" && <SliderInput id="volume" label="Volume of Solution (L)" value={volume} min={0.001} max={100} step={0.001} onChange={setVolume} format={v => `${v.toFixed(3)} L`} testId="input-volume" />}
            {solveFor !== "molarity" && <SliderInput id="molarity" label="Molarity (M)" value={molarity} min={0.001} max={20} step={0.001} onChange={setMolarity} format={v => `${v.toFixed(3)} M`} testId="input-molarity" />}
          </div>
          <motion.div key={`${solveFor}-${result}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-cyan-500 to-cyan-700 rounded-2xl p-6 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{label}</p>
              <p className="text-5xl font-black text-white tracking-tight" data-testid="result-value">{result.toFixed(4)} {unit}</p>
              <p className="text-white/70 text-sm mt-1">M = n / V (Molarity = Moles  x  Liters)</p>
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Molarity of Any Solution for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Molarity is the standard way to express solution concentration in chemistry. It tells you how many moles of solute are dissolved in each liter of solution. This is important because chemical reactions occur in specific molar ratios - knowing concentration lets you calculate exactly how much of each reactant to use.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Molarity (M) = Moles of solute (n) / Volume of solution (V in liters)</p>
            <p>Moles = Molarity  x  Volume</p>
            <p>Volume = Moles / Molarity</p>
            <p className="text-xs text-muted-foreground mt-2">Dilution equation: M1 x V1 = M2 x V2</p>
            <p className="text-xs text-muted-foreground">Moles from mass: n = mass (g) / molar mass (g/mol)</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How the Molarity Formula M = n/V Works</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Molarity", "100 mL", "250 mL", "500 mL", "1 L", "2 L"].map(h => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {concentrationRows.map(m => (
                  <tr key={m} className={`hover:bg-muted/30 ${solveFor === "molarity" && Math.abs(m - result) < 0.05 ? "bg-cyan-50 dark:bg-cyan-950/20 font-semibold" : ""}`}>
                    <td className="py-2.5 px-3 font-bold text-cyan-600 dark:text-cyan-400">{m} M</td>
                    {[0.1, 0.25, 0.5, 1, 2].map(v => (
                      <td key={v} className="py-2.5 px-3 text-muted-foreground">{(m * v).toFixed(4)} mol</td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Chemistry Molarity Tool for Students and Professionals</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Solution", "Molarity", "Notes"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {COMMON_CONCENTRATIONS.map(([solution, molarity_, notes]) => (
                  <tr key={solution} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{solution}</td>
                    <td className="py-2.5 px-4 text-cyan-600 dark:text-cyan-400 font-bold">{molarity_}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{notes}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/molarity-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


